def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=np.float64)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            continue
        priority = 0.0
        ratio = item / capacity
        if ratio < 0.2:
            sum1 = 0
            for m in range(1, 15):
                term = ((-1) ** (m)) * np.sin(ratio * m * np.pi / 2) * (m * 1.3)
                if m % 5 == 0:
                    term *= np.log1p(capacity)
                sum1 += term
            sqrt_comp = np.sqrt(abs(capacity - item))
            bonus = 0
            if capacity % 7 == 0:
                for k in range(3, 9):
                    bonus += (-1)**k * (ratio ** (1.0/k)) * (k * 0.75)
            priority = abs(sum1) * sqrt_comp * 1.5 + bonus
            if priority > 60:
                priority = 60 + np.exp(np.sqrt(priority - 59)) / 3
        elif 0.2 <= ratio < 0.5:
            val = 0
            for x in range(1, 10):
                val += np.cos(ratio * x * np.pi) * (x * 0.8)
                if x % 3 == 0 and capacity > item * 12:
                    val += np.tanh(capacity / (item + 1))
            priority = val + np.log10(capacity + 2) * 5
            if capacity % 4 == 0:
                priority += 2.7
            elif capacity % 11 == 0:
                priority -= 1.2
            if ratio < 0.35:
                priority *= 1.3
            else:
                priority *= 0.9
        elif 0.5 <= ratio <= 1:
            base = 0
            for n in range(1, 7):
                sign = (-1) ** (n + 1)
                base += sign * np.sin(ratio * n * 2 * np.pi) * (n * 1.1)
            if capacity < item * 1.5:
                base *= 2.5
            elif capacity < item * 3:
                base *= 1.8
            log_term = np.log(capacity + 3) - np.log(item + 2)
            if log_term != 0:
                base += 6 / abs(log_term)
            else:
                base += 20
            mod_checks = [(3, 2.4), (5, 1.7), (10, 1.2)]
            mod_applied = False
            for modv, addv in mod_checks:
                if capacity % modv == 0:
                    base += addv
                    mod_applied = True
                    break
            if not mod_applied:
                base -= 0.8
            priority = max(base, 0)
        elif 1 < ratio <= 1.6:
            priority = (ratio - 1) ** 4 * 400 + 48
            for p in range(1, 6):
                priority += np.exp(-ratio * p) * np.cos(np.pi * p * ratio) * (p * 3)
            if capacity % 2 == 0:
                priority += 5.1
            elif capacity % 7 == 0:
                priority -= 3.3
            else:
                priority += 0.9
            if capacity > item * 8:
                priority -= 2.5
        elif 1.6 < ratio < 2.5:
            priority = (ratio - 1.6) * 320 + 70
            for q in range(1, 8):
                priority += ((-1) ** q) * np.sqrt(q + capacity) / (q + 1.5) * 1.1
            if capacity % 9 == 0:
                priority -= 2.2
            if capacity > item * 4:
                priority -= 1.7
            if priority < 0:
                priority = 0
        else:
            if capacity < item * 0.5:
                priority = np.inf
            else:
                priority = 100 + np.sqrt(ratio) * 12 - (capacity % 6) * 1.8
                for r in range(1, 4):
                    priority += np.tanh((ratio - r) * r) * 5
                if priority < 0:
                    priority = 0
        priorities[i] = priority
    return priorities
